module top_module(CLK, D, reset, Q);input CLK, D, reset;
output Q;
reg Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge reset or posedge dbg_halt) begin
    if (reset) begin
        Q <= 0;
    end else begin
        Q <= D;
    end
end

endmodule
